inline std::unordered_map<std::string, const char*>& activeMap() {
    static std::unordered_map<std::string, const char*> m; static int builtFor = -1;
    if (builtFor != g_lang) { m.clear(); builtFor = g_lang;
        if (g_lang != EN) { size_t n; const Entry* Tarr = table(n);
            for (size_t i=0;i<n;i++) { const char* v = Tarr[i].t[g_lang]; if (v && *v && Tarr[i].t[EN]) m[Tarr[i].t[EN]] = v; } } }
    return m;
}
inline const char* tr(const char* s) {
    if (g_lang == EN || !s || !*s) return s;
    auto& m = activeMap(); auto it = m.find(s); return it == m.end() ? s : it->second;
}

// Every non-ASCII codepoint any translation uses, so the font atlas bakes exactly those glyphs.
inline void collectExtraCodepoints(std::vector<unsigned>& out) {
    out.clear(); std::unordered_map<unsigned,char> seen;
    auto scan=[&](const char* s){ if(!s)return; const char* p=s; while(*p){ unsigned cp=utf8Next(p); if(cp>=0x80&&!seen.count(cp)){ seen[cp]=1; out.push_back(cp);} } };
    size_t n; const Entry* Tarr = table(n); for (size_t i=0;i<n;i++) for (int l=1;l<LANG_COUNT;l++) scan(Tarr[i].t[l]);
    size_t ln; auto* Larr=langs(ln); for (size_t i=0;i<ln;i++) scan(Larr[i].name);
}

